import{_ as e,o as a,c as d,S as r}from"./chunks/framework.DZlzLDBr.js";const p=JSON.parse('{"title":"Settings","description":"","frontmatter":{},"headers":[],"relativePath":"Settings.md","filePath":"Settings.md","lastUpdated":null}'),n={name:"Settings.md"};function i(o,t,s,h,l,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Open <strong>Settings → Community plugins → Sprout</strong> to configure the plugin.</p><p>Settings are grouped by tab.</p><h2 id="user-details" tabindex="-1">User details <a class="header-anchor" href="#user-details" aria-label="Permalink to &quot;User details&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>User name</td><td><em>(empty)</em></td><td>Name shown in greetings on the home page</td></tr><tr><td>Show Sprout information on the homepage</td><td>On</td><td>Display developer info on the home view</td></tr><tr><td>Show greeting text</td><td>On</td><td>Personalised greeting vs plain &quot;Home&quot; title</td></tr></tbody></table><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Enable animations</td><td>On</td><td>Page-load fade-up animations</td></tr></tbody></table><h2 id="reminders-and-gatekeeper" tabindex="-1">Reminders and Gatekeeper <a class="header-anchor" href="#reminders-and-gatekeeper" aria-label="Permalink to &quot;Reminders and Gatekeeper&quot;">​</a></h2><p>Reminders and Gatekeeper are documented on dedicated pages:</p><ul><li><a href="./Reminders">Reminders</a> — gentle launch/routine nudges</li><li><a href="./Gatekeeper">Gatekeeper</a> — enforced review popups and bypass behavior</li></ul><h2 id="image-occlusion" tabindex="-1">Image Occlusion <a class="header-anchor" href="#image-occlusion" aria-label="Permalink to &quot;Image Occlusion&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Default IO attachment folder</td><td><code>Attachments/Image Occlusion/</code></td><td>Where IO images are saved</td></tr><tr><td>Delete orphaned IO images</td><td>On</td><td>Auto-delete IO images when their cards are removed</td></tr></tbody></table><h2 id="card-attachments" tabindex="-1">Card Attachments <a class="header-anchor" href="#card-attachments" aria-label="Permalink to &quot;Card Attachments&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Card attachment folder</td><td><code>Attachments/Cards/</code></td><td>Where card media (images, audio) is saved</td></tr></tbody></table><h2 id="study" tabindex="-1">Study <a class="header-anchor" href="#study" aria-label="Permalink to &quot;Study&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Daily new limit</td><td>20</td><td>Max new cards per scope per day</td></tr><tr><td>Daily review limit</td><td>200</td><td>Max due cards per scope per day</td></tr><tr><td>Auto-advance</td><td>Off</td><td>Auto-fail and advance unanswered cards</td></tr><tr><td>Auto-advance after</td><td>60 s</td><td>Seconds before auto-advancing (3–60)</td></tr><tr><td>Grading buttons</td><td>Two buttons</td><td><strong>Two</strong> (Again / Good) or <strong>Four</strong> (Again / Hard / Good / Easy). See <a href="./Grading">Grading</a>.</td></tr><tr><td>Skip button</td><td>Off</td><td>Show a Skip button (Enter) in the reviewer</td></tr><tr><td>Randomise MCQ options</td><td>Off</td><td>Shuffle MCQ option order each time</td></tr><tr><td>Show info by default</td><td>Off</td><td>Expand the info field on the card back</td></tr></tbody></table><p>Daily limits reset at midnight and are tracked per scope.</p><h2 id="widget" tabindex="-1">Widget <a class="header-anchor" href="#widget" aria-label="Permalink to &quot;Widget&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Treat folder notes as decks</td><td>On</td><td>Folder notes act as deck roots for their folder. See <a href="./Widget">Widget</a>.</td></tr></tbody></table><h2 id="scheduling-fsrs" tabindex="-1">Scheduling (FSRS) <a class="header-anchor" href="#scheduling-fsrs" aria-label="Permalink to &quot;Scheduling (FSRS)&quot;">​</a></h2><p>Sprout uses <strong>FSRS</strong>. Choose a preset or edit values manually.</p><p>See <a href="./Scheduling">Scheduling</a> for details.</p><h3 id="presets" tabindex="-1">Presets <a class="header-anchor" href="#presets" aria-label="Permalink to &quot;Presets&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Preset</th><th>Learning steps</th><th>Relearning steps</th><th>Retention</th></tr></thead><tbody><tr><td>Relaxed</td><td>20 min</td><td>20 min</td><td>0.88</td></tr><tr><td>Balanced</td><td>10 min, 1 day</td><td>10 min</td><td>0.90</td></tr><tr><td>Aggressive</td><td>5 min, 30 min, 1 day</td><td>10 min</td><td>0.92</td></tr><tr><td>Custom</td><td><em>(user-defined)</em></td><td><em>(user-defined)</em></td><td><em>(user-defined)</em></td></tr></tbody></table><h3 id="manual-options" tabindex="-1">Manual options <a class="header-anchor" href="#manual-options" aria-label="Permalink to &quot;Manual options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Learning steps</td><td><code>10, 1440</code></td><td>Minutes between learning steps (comma-separated)</td></tr><tr><td>Relearning steps</td><td><code>10</code></td><td>Minutes between relearning steps</td></tr><tr><td>Requested retention</td><td>0.90</td><td>Target recall probability (0.80–0.97)</td></tr></tbody></table><h2 id="indexing" tabindex="-1">Indexing <a class="header-anchor" href="#indexing" aria-label="Permalink to &quot;Indexing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Ignore fenced code blocks</td><td>On</td><td>Skip card syntax inside fenced code blocks</td></tr><tr><td>Card delimiter</td><td>Pipe <code>|</code></td><td>Character used to separate card fields. See <a href="./Custom-Delimiters">Custom Delimiters</a>.</td></tr><tr><td>ID placement</td><td>Above</td><td>Place card anchors above or below the card block</td></tr></tbody></table><p>If the delimiter is changed, card parsing behavior changes on next sync.</p><h2 id="danger-zone" tabindex="-1">Danger zone <a class="header-anchor" href="#danger-zone" aria-label="Permalink to &quot;Danger zone&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Effect</th></tr></thead><tbody><tr><td>Delete all flashcards</td><td>Removes <strong>all</strong> Sprout data from every note and the plugin store. This cannot be undone.</td></tr></tbody></table><h2 id="quarantined-cards" tabindex="-1">Quarantined cards <a class="header-anchor" href="#quarantined-cards" aria-label="Permalink to &quot;Quarantined cards&quot;">​</a></h2><p>If a card cannot be parsed (for example, malformed syntax), it is listed here with its ID and error.</p><p>Use <strong>Open note</strong> to jump to the source, fix the syntax, then sync again. See <a href="./Syncing">Syncing</a>.</p>',36)])])}const b=e(n,[["render",i]]);export{p as __pageData,b as default};
